CREATE TABLE IF NOT EXISTS varshaphala (
    id                   UUID         PRIMARY KEY DEFAULT gen_random_uuid(),
    chart_id             TEXT         NOT NULL,
    year                 INTEGER      NOT NULL,
    solar_return_utc     TIMESTAMPTZ  NOT NULL,
